/**
 * Retailization Industry Packs — 40 industry-specific AMC sub-packs
 * Based on the Retailization framework by Subbu Iyer
 * 7 stations: Environment, Health, Wealth, Education, Mobility, Technology, Governance
 */
import type { Domain } from "./domainRegistry.js";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type IndustryPackId =
  | "farm-to-fork"
  | "weave-to-wear"
  | "material-to-machines"
  | "source-to-sustenance"
  | "ubiquity-to-utility"
  | "sip-to-sanitation"
  | "digital-health-record"
  | "wellness-management"
  | "patient-lifecycle"
  | "clinical-lifecycle"
  | "professional-practice"
  | "life-technology"
  | "drug-discovery"
  | "clinical-trials"
  | "specialized-medicine"
  | "future-of-work"
  | "digital-payments"
  | "no-poverty"
  | "circular-economy"
  | "blockchain"
  | "k12-pm3"
  | "higher-education"
  | "skills-training"
  | "specialized-education"
  | "differently-abled"
  | "sustainable-communities"
  | "sustainable-ports"
  | "sustainable-real-estate"
  | "virtual-infrastructure"
  | "privacy-security-mobility"
  | "cognition-to-intelligence"
  | "networked-ecosystems"
  | "os-sustainable-outcomes"
  | "infotainment"
  | "partnerships-prosperity"
  | "digital-citizens-rights"
  | "dance-of-democracy"
  | "petition-to-law"
  | "citizen-services"
  | "public-private-collaboration";

export interface IndustryPackQuestion {
  id: string;
  dimension: string;
  text: string;
  regulatoryRef: string;
  l1: string;
  l3: string;
  l5: string;
  weight: number;
}

export interface IndustryPack {
  id: IndustryPackId;
  stationId: Domain;
  name: string;
  description: string;
  regulatoryBasis: string[];
  questions: IndustryPackQuestion[];
  certificationThreshold: number;
  complianceFrameworks: string[];
  /**
   * Industry-specific risk tier — distinct from core RiskTier ("low"|"med"|"high"|"critical").
   * Sector packs use regulatory-aligned tiers: critical > very-high > high > elevated.
   */
  riskTier: "critical" | "very-high" | "high" | "elevated";
  euAIActClassification: string;
  sdgAlignment: string[];
  certificationPath: string;
  keyRisks: string[];
}

export interface IndustryPackAssessment {
  packId: IndustryPackId;
  responses: Record<string, number>;
}

// IndustryPackScoreResult is defined later in the functions section.

// ---------------------------------------------------------------------------
// Helper to build packs
// ---------------------------------------------------------------------------

function q(
  id: string,
  dimension: string,
  text: string,
  regulatoryRef: string,
  l1: string,
  l3: string,
  l5: string,
  weight: number
): IndustryPackQuestion {
  return { id, dimension, text, regulatoryRef, l1, l3, l5, weight };
}

